/**
 * @name Expression Language injection via cron input
 * @description User-controlled cron strings may reach Expression Language evaluation sinks
 * @kind path-problem
 * @problem.severity error
 * @id java/el-injection-cron
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ElInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // javax.el EL evaluation
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ELProcessor") and
      sink.asExpr() = mc.getArgument(0)
    ) or
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ValueExpression") and
      sink.asExpr() = mc.getQualifier()
    ) or
    exists(MethodCall mc |
      mc.getMethod().hasName("createValueExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ExpressionFactory") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ElInjectionFlow = TaintTracking::Global<ElInjectionConfig>;
import ElInjectionFlow::PathGraph

from ElInjectionFlow::PathNode source, ElInjectionFlow::PathNode sink
where ElInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential EL injection from $@.", source.getNode(), "user input"

/**
 * @name EL injection via Bean Validation constraint messages
 * @description User-controlled input used in validation constraint messages may be evaluated as EL expressions
 * @kind path-problem
 * @problem.severity error
 * @id java/el-injection-validation-message
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Find where validation constraint violation messages are constructed with user input
module ELValidationConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Method parameters in public API methods that accept cron strings
    exists(Method m, Parameter p |
      m.isPublic() and
      p = m.getAParameter() and
      p.getType() instanceof TypeString and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ConstraintValidatorContext.buildConstraintViolationWithTemplate
    exists(MethodCall mc |
      mc.getMethod().hasName("buildConstraintViolationWithTemplate") and
      sink.asExpr() = mc.getArgument(0)
    ) or
    // interpolateMessage with EL
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolate") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ELValidationFlow = TaintTracking::Global<ELValidationConfig>;
import ELValidationFlow::PathGraph

from ELValidationFlow::PathNode source, ELValidationFlow::PathNode sink
where ELValidationFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential EL injection via constraint violation message from $@.", source.getNode(), "user-controlled input"

/**
 * @name Full taint flow from cron string parameter to buildConstraintViolationWithTemplate
 * @description Trace user-controlled cron string through exception message to EL template
 * @kind path-problem
 * @problem.severity error
 * @id java/cron-el-injection-full-path
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking

module CronELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The cron string parameter in CronValidator.isValid(String value, ...)
    exists(Method m, Parameter p |
      m.hasName("isValid") and
      m.getDeclaringType().hasQualifiedName("com.cronutils.validation", "CronValidator") and
      p = m.getParameter(0) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("buildConstraintViolationWithTemplate") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module CronELFlow = TaintTracking::Global<CronELConfig>;
import CronELFlow::PathGraph

from CronELFlow::PathNode source, CronELFlow::PathNode sink
where CronELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "EL injection: cron string flows to buildConstraintViolationWithTemplate from $@.", source.getNode(), "cron string parameter"

/**
 * @name EL injection via exception message in CronValidator
 * @description Cron string flows into exception message then into buildConstraintViolationWithTemplate causing EL injection
 * @kind path-problem
 * @problem.severity error
 * @id java/cron-el-injection-via-exception
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking

module CronELExceptionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The cron string parameter in CronValidator.isValid
    exists(Method m, Parameter p |
      m.hasName("isValid") and
      m.getDeclaringType().hasQualifiedName("com.cronutils.validation", "CronValidator") and
      p = m.getParameter(0) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("buildConstraintViolationWithTemplate") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node node1, DataFlow::Node node2) {
    // Track taint through exception getMessage() calls
    // If a tainted value flows into an exception constructor, the exception's getMessage() is also tainted
    exists(ClassInstanceExpr cie, MethodCall mc |
      cie.getAnArgument() = node1.asExpr() and
      mc.getQualifier() = node2.asExpr() and
      mc.getMethod().hasName("getMessage") and
      // The exception variable connecting them
      exists(LocalVariableDecl v |
        DataFlow::localFlow(DataFlow::exprNode(cie), DataFlow::exprNode(v.getAnAccess()))
      )
    )
    or
    // Exception getMessage() returns the message that was passed in constructor
    exists(MethodCall mc |
      mc.getMethod().hasName("getMessage") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "Throwable") and
      node1.asExpr() = mc.getQualifier() and
      node2.asExpr() = mc
    )
    or
    // Track through exception constructor: new SomeException(taintedString) -> exception object is tainted
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "Throwable") and
      node1.asExpr() = cie.getAnArgument() and
      node2.asExpr() = cie
    )
  }
}

module CronELExceptionFlow = TaintTracking::Global<CronELExceptionConfig>;
import CronELExceptionFlow::PathGraph

from CronELExceptionFlow::PathNode source, CronELExceptionFlow::PathNode sink
where CronELExceptionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "EL injection: cron string flows through exception message to buildConstraintViolationWithTemplate from $@.", source.getNode(), "cron string parameter"

/**
 * @name Verify cron string is embedded in parse exception messages
 * @description Confirm that the user-supplied cron string value is included in exception messages thrown by CronParser.parse
 * @kind path-problem
 * @problem.severity error
 * @id java/cron-parser-exception-user-input
 * @tags security
 *       external/cwe/cwe-917
 */
import java
import semmle.code.java.dataflow.TaintTracking

module ParseExceptionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The value parameter in CronParser.parse(String expression)
    exists(Method m, Parameter p |
      m.hasName("parse") and
      m.getDeclaringType().hasQualifiedName("com.cronutils.parser", "CronParser") and
      p = m.getParameter(0) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Any exception constructor argument in parse or called methods
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "Throwable") and
      sink.asExpr() = cie.getAnArgument()
    )
  }
}

module ParseExceptionFlow = TaintTracking::Global<ParseExceptionConfig>;
import ParseExceptionFlow::PathGraph

from ParseExceptionFlow::PathNode source, ParseExceptionFlow::PathNode sink
where ParseExceptionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User cron input flows into exception message from $@.", source.getNode(), "cron expression parameter"
